<template >
    <div id = "app" >
        <div class = "events content" >
            <div class = "events-filter" >
                <div class = "select" >
                    <div class = "select-selection" >
                        <div class = "select__label" >Организация</div >
                        <input class = "select__current"
                               :value = "filters.company.current"
                               readonly >
                        <svg class = "select-arrow" >
                            <use xlink:href = "./assets/icons.svg#chevron" ></use >
                        </svg >
                    </div >
                    <div class = "select-dropdown" >
                        <div class = "select-dropdown-item --current" >
                            <span >Все организации</span >
                        </div >
                        <template v-for = "(i, k) in filters.company.values" >
                            <div class = "select-dropdown-item"
                                 :key = "k" >
                                <span >{{i}}</span >
                            </div >
                        </template >
                    </div >
                </div >
                <div class = "select" >
                    <div class = "select-selection" >
                        <div class = "select__label" >Месяц</div >
                        <input class = "select__current"
                               :value = "filters.date.current"
                               readonly >
                        <svg class = "select-arrow" >
                            <use xlink:href = "./assets/icons.svg#chevron" ></use >
                        </svg >
                    </div >
                    <div class = "select-dropdown" >
                        <div class = "select-dropdown-item --current" >
                            <span >Все время</span >
                        </div >
                        <template v-for = "(i, k) in filters.date.values" >
                            <div class = "select-dropdown-item"
                                 :key = "k" >
                                <span >{{i}}</span >
                            </div >
                        </template >
                    </div >
                </div >
                <div class = "select" >
                    <div class = "select-selection" >
                        <div class = "select__label" >Статус</div >
                        <input class = "select__current"
                               :value = "filters.status.current"
                               @input = "console.log($event)"
                               @change = "console.log($event)"
                               readonly >
                        <svg class = "select-arrow" >
                            <use xlink:href = "./assets/icons.svg#chevron" ></use >
                        </svg >
                    </div >
                    <div class = "select-dropdown" >
                        <div class = "select-dropdown-item --current" >
                            <span >Все статусы</span >
                        </div >
                        <template v-for = "(i, k) in filters.status.values" >
                            <div class = "select-dropdown-item"
                                 :key = "k" >
                                <span class = "event-status"
                                      :class = "i === 'Выполнено' ? '--ok' : i === 'Запланировано' ? '--pending' : i === 'Просрочено' ? '--failed' : ''" >
                                    {{i}}
                                </span >
                            </div >
                        </template >
                    </div >
                </div >
            </div >
            <template v-for = "(c, key) in  list" >
                <div v-if = "c.events.length > 0"
                     :key = "key"
                     class = "events-group" >
                    <p class = "subtext summ events-group__title" >{{c.name}}</p >
                    <div v-for = "(e, key) in c.events"
                         :key = "key" class = "event-item" >
                        <div class = "event-item__date caption" >{{e.date}}</div >
                        <div class = "event-item__topic subtext" >{{e.topic}}</div >
                        <div class = "event-item__status subtext" >
                            <span class = "event-status"
                                  :class = "e.status === 'Выполнено' ? '--ok' : e.status === 'Запланировано' ? '--pending' : e.status === 'Просрочено' ? '--failed' : ''" >
                                {{e.status}}
                            </span >
                        </div >
                    </div >
                </div >
            </template >
        </div >
        <notes ></notes >
    </div >
</template >

<script >
  import axios from "axios";
  import notifications from "./components/notifications";
  import {Select} from "./includes/scripts/_select";

  const months = {
    "1": "Январь",
    "2": "Февраль",
    "3": "Март",
    "4": "Апрель",
    "5": "Май",
    "6": "Июнь",
    "7": "Июль",
    "8": "Август",
    "9": "Сентябрь",
    "10": "Октябрь",
    "11": "Ноябрь",
    "12": "Декабрь",
  };

  export default {
    name: "events",
    data() {
      return {
        list: [],
        filters: {
          company: {
            current: "Все организации",
            values: [],
          },
          date: {
            current: "Все время",
            values: [],
          },
          status: {
            current: "Все статусы",
            values: [],
          },
        },
      };
    },
    components: {
      notes: notifications,
    },
    methods: {
      getCompanies: function () {
        axios.get(
            "/json/organizations.json",
            {
              headers: {
                "Content-Type": "application/json",
              },
            },
        ).then(response => {
          this.list = response.data;
          this.getFilters();
        }).catch(error => console.error(error));
      },
      getFilters: function () {
        this.list.forEach((company) => {
          // добавить значение в список фильтрации по организациям
          this.filters.company.values.push(company.name);

          company.events.forEach(event => {
            // добавить значение в список фильтрации по статусу
            if (!this.filters.status.values.includes(event.status) && event.status) {
              this.filters.status.values.push(event.status);
            }

            // добавить значение в список фильтрации по месяцам
            let num = event.date.split(".")[1],
                month = months[num] + " " + event.date.split(".")[2];
            if (!this.filters.date.values.includes(month.value) && month) {
              this.filters.date.values.push(Object.assign({value: month}));
            }
          });
        });
      },
    },
    mounted() {
      this.getCompanies();
      this.$el.querySelectorAll(".select").forEach(el => {
        // eslint-disable-next-line
        let select = new Select(el);
      });
    },
  };
</script >

<style >
    @import url('https://fonts.googleapis.com/css2?family=PT+Sans:ital,wght@0,400;0,700;1,400;1,700&display=swap');
    @import "includes/styles/_reset.css";
    @import 'includes/styles/_typo.css';
    @import 'includes/styles/_template.css';
    @import "includes/styles/_select.css";

    .events {
        margin-top: 20px;
        margin-bottom: 20px;
        }

    .events-filter {
        display: grid;
        margin-bottom: 30px;
        grid-gap: 12px;
        grid-template-columns: repeat(auto-fit, 250px);
        }

    .events-group:not(:last-child) {
        margin-bottom: 30px;
        }

    .events-group .events-group__title {
        margin-bottom: 12px;
        }

    .event-item {
        display: flex;
        padding: 13px 15px;
        flex-direction: row;
        align-items: center;
        background: #FFFFFF;
        border-radius: 6px;
        box-shadow: 0 0 7px rgba(0, 0, 0, 0.05);
        }

    .event-item .event-item__date {
        padding: 6px 8px;
        background: #F7F7F7;
        border-radius: 6px;
        }

    .event-item .event-item__topic {}

    .event-item .event-item__status {
        min-width: 125px;
        margin-left: auto;
        }

    .event-status {
        position: relative;
        padding-left: 22px;
        }

    .event-status::before {
        content: '';
        position: absolute;
        left: 0;
        top: calc(50% - 5px);
        display: block;
        width: 12px;
        height: 12px;
        border-radius: 50%;
        }

    .event-status.--ok::before {background-color: #94C530;}

    .event-status.--pending::before {background-color: #FEDD46;}

    .event-status.--failed::before {background-color: #F55F44;}

    .event-item:not(:last-child) {margin-bottom: 5px;}

    @media (max-width: 575px) {
        .event-item {
            flex-wrap: wrap;
            }
        .event-item .event-item__date,
        .event-item .event-item__status {margin-bottom: 10px;}
        .event-item .event-item__date {order: 1;}

        .event-item .event-item__topic {
            order: 3;
            width: 100%;
            flex: 1 1 100%;
            }

        .event-item .event-item__status {order: 2;}
        }

    @media (min-width: 576px) {
        .event-item .event-item__topic:not(:first-child) {margin-left: 40px;}
        .event-item .event-item__topic:not(:last-child) {margin-right: 20px;}
        }
</style >
