export class Select {
  constructor(el) {
    this.$el = el;
    this.$selection = el.querySelector(".select-selection");
    this.$dropdown = el.querySelector(".select-dropdown");

    this.init();
  }

  init = () => {
    if(!this.$dropdown.querySelector("--current")) {
      this.selectOption(this.$dropdown.querySelectorAll(".select-dropdown-item")[0])
    }

    this.$selection.addEventListener("click", () => {
      this.$el.classList.toggle("--opened");
    });

    document.addEventListener("click", (event) => {
      if (!this.$el.contains(event.target)) {
        this.$el.classList.remove("--opened");
      } else if (this.$dropdown.contains(event.target)) {
        this.selectOption(event.target.closest(".select-dropdown-item"));
      }
    });
  };
  selectOption = (itm) => {
    if (!itm.classList.contains("--current")) {
      this.$selection.querySelector(".select__current").value = itm.innerText;
      this.$dropdown.querySelector(".select-dropdown-item.--current")?.classList.remove("--current");
      itm.classList.add("--current");
    }

  };
}